from checkers.board import Board
from checkers.piece import Piece, King
from checkers.utils import get_opposite_color, is_valid_move, is_valid_capture

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'white'

    def run(self):
        while True:
            print(self.board)
            move = input(f"{self.current_player} enter your move (e.g., 'a1-a3'): ")
            if self.make_move(move):
                if self.check_winner():
                    print(f"{get_opposite_color(self.current_player)} wins!")
                    break
                self.switch_player()
            else:
                print("Invalid move. Try again.")

    def make_move(self, move):
        start_pos, end_pos = move.split('-')
        piece = self.board.get_piece(start_pos)
        if piece and piece.color == self.current_player:
            if is_valid_move(piece, start_pos, end_pos, self.board) or is_valid_capture(piece, start_pos, end_pos, self.board):
                self.board.move_piece(start_pos, end_pos)
                return True
        return False

    def switch_player(self):
        self.current_player = get_opposite_color(self.current_player)

    def check_winner(self):
        opponent_pieces = [piece for row in self.board.state for piece in row if piece and piece.color != self.current_player]
        if not opponent_pieces:
            return True
        return False
