class Board:
    def __init__(self, size=8):
        self.size = size
        self.state = [[None] * size for _ in range(size)]
        self.init_board()

    def init_board(self):
        colors = ['white', 'black']
        for i in range(3):
            color_index = i % 2
            for j in range(4):
                if (i + j) % 2 == 0:
                    self.state[i][j * 2] = Piece(color=colors[color_index])

    def get_piece(self, pos):
        x, y = int(pos[1]) - 1, ord(pos[0]) - ord('a')
        return self.state[x][y]

    def move_piece(self, start_pos, end_pos):
        x_start, y_start = int(start_pos[1]) - 1, ord(start_pos[0]) - ord('a')
        x_end, y_end = int(end_pos[1]) - 1, ord(end_pos[0]) - ord('a')
        self.state[x_end][y_end] = self.state[x_start][y_start]
        self.state[x_start][y_start] = None

    def __str__(self):
        board_str = '  a b c d e f g h\n'
        for i in range(self.size):
            row_str = f"{i+1} "
            for j in range(self.size):
                piece = self.state[i][j]
                if piece:
                    row_str += f"[{piece.color[0]}] "
                else:
                    row_str += ".   "
            board_str += row_str + '\n'
        return board_str
```

