def get_opposite_color(color):
    return 'black' if color == 'white' else 'white'

def is_valid_move(piece, start_pos, end_pos, board):
    x_start, y_start = int(start_pos[1]) - 1, ord(start_pos[0]) - ord('a')
    x_end, y_end = int(end_pos[1]) - 1, ord(end_pos[0]) - ord('a')
    dx, dy = abs(x_start - x_end), abs(y_start - y_end)
    if dx == dy == 1 and board.state[x_end][y_end] is None:
        return True
    return False

def is_valid_capture(piece, start_pos, end_pos, board):
    x_start, y_start = int(start_pos[1]) - 1, ord(start_pos[0]) - ord('a')
    x_end, y_end = int(end_pos[1]) - 1, ord(end_pos[0]) - ord('a')
    dx, dy = abs(x_start - x_end), abs(y_start - y_end)
    if dx == 2 and dy == 2:
        mid_x, mid_y = (x_start + x_end) // 2, (y_start + y_end) // 2
        if board.state[mid_x][mid_y] and board.state[mid_x][mid_y].color != piece.color and board.state[x_end][y_end] is None:
            return True
    return False
