# checkers.py

import re
from enum import Enum

class Color(Enum):
    EMPTY = 0
    WHITE = 1
    BLACK = 2

class Piece:
    def __init__(self, color):
        self.color = color

class Square:
    def __init__(self, piece=None):
        self.piece = piece

class Board:
    def __init__(self):
        self.squares = [[Square() for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = [Color.WHITE, Color.BLACK] * 4
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.squares[row][col].piece = Piece(colors[row % 2])
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.squares[row][col].piece = Piece(colors[row % 2])

    def move_piece(self, from_square, to_square):
        piece = self.squares[from_square[0]][from_square[1]].piece
        if not piece:
            raise ValueError("No piece to move")
        if piece.color == Color.EMPTY:
            raise ValueError("Selected square is empty")

        self.squares[to_square[0]][to_square[1]].piece = piece
        self.squares[from_square[0]][from_square[1]].piece = Square()

        # Promote to king if necessary
        if to_square[0] == 0 and piece.color == Color.WHITE:
            self.squares[to_square[0]][to_square[1]].piece.color = Color.WHITE_KING
        elif to_square[0] == 7 and piece.color == Color.BLACK:
            self.squares[to_square[0]][to_square[1]].piece.color = Color.BLACK_KING

    def capture_piece(self, from_square, capture_square):
        captured_piece = self.squares[capture_square[0]][capture_square[1]].piece
        if not captured_piece:
            raise ValueError("No piece to capture")
        if captured_piece.color == Color.EMPTY:
            raise ValueError("Selected square is empty")

        self.squares[from_square[0]][from_square[1]].piece = None
        self.squares[capture_square[0]][capture_square[1]].piece = None

    def print_board(self):
        for row in range(8, 0, -1):
            print(" ", end="")
            for col in range(8):
                if self.squares[row-1][col].piece:
                    if self.squares[row-1][col].piece.color == Color.WHITE or self.squares[row-1][col].piece.color == Color.BLACK_KING:
                        print('W', end=" ")
                    elif self.squares[row-1][col].piece.color == Color.BLACK or self.squares[row-1][col].piece.color == Color.WHITE_KING:
                        print('B', end=" ")
                else:
                    print('.', end=" ")
            print()

def get_move():
    move = input("Enter your move (e.g., '42 53'): ")
    match = re.match(r'(\d)(\d) (\d)(\d)', move)
    if not match:
        raise ValueError("Invalid move format")
    return [int(match.group(1)), int(match.group(2))], [int(match.group(3)), int(match.group(4))]

def main():
    board = Board()
    current_player = Color.WHITE

    while True:
        board.print_board()

        try:
            from_square, to_square = get_move()
            if (from_square[0] + from_square[1]) % 2 == 0 or (to_square[0] + to_square[1]) % 2 == 0:
                raise ValueError("Invalid square selection")
            board.move_piece(from_square, to_square)
        except Exception as e:
            print(f"Error: {e}")

if __name__ == "__main__":
    main()
